sql:
SELECT album_id, album_name, tracks AS total_tracks
FROM albums
WHERE album_name = 'Example Album';

SELECT DISTINCT a.album_name
FROM albums a
JOIN ratings r ON a.album_id = r.album_id;

external_knowledge:
- "musical voyages" refers to albums;
- "sailed more than once across the ocean of listeners' attention" indicates that the album has been listened to more than once;
- "ranked by the frequency of their voyages" means the albums are ordered by the count of listens in descending order.

Classic albums: Albums released between 1980 and 1990;
Overall reception: Measured by the average rating;
Positive feedback: Average rating greater than 4 and over 10 ratings.

sql:
SELECT AVG(tracks) AS average_tracks_per_folk_album
FROM albums
WHERE genre = 'Folk';
